/**
 * Experiment decision engine — given an A/B test result, recommend
 * ship / iterate / kill based on lift, sample size, and confidence.
 *
 * Uses a frequentist two-proportion z-test for statistical significance
 * and Bayesian reasoning for sample-size adequacy.
 */
import { db } from "@/lib/db";

export interface ExperimentData {
  variant_a_users: number;
  variant_a_conversions: number;
  variant_b_users: number;
  variant_b_conversions: number;
}

export type Verdict = "ship" | "iterate" | "keep_running" | "kill";

export interface Decision {
  verdict: Verdict;

/**
 * Sales sequences — multi-step outbound cadences.
 *
 * Step shape:
 *   { day: number, channel: 'email' | 'task' | 'linkedin', subject?, body?, task_title?, delay_hours? }
 *
 * On enrollment:
 *   - contact gets step 1 at enroll time (delay 0)
 *   - subsequent steps fire at next_action_at = previous_action_at + step.day * 86400000
 *   - if contact replies, sequence pauses (status='replied')
 *   - if sequence books a meeting, status='booked'
 */
import { db, uid, now } from "@/lib/db";

export interface SequenceStep {
  day: number;
  channel: "email" | "task" | "linkedin";
  subject?: string;
  body?: string;
  task_title?: string;

/**
 * Deal Intelligence — analyze deal risk + recommend actions.
 *
 * Phase 3 OSS integration. Ported from GTM Engine (sohan-a11y/gtm-engine)
 * Deal Intelligence Agent. Analyzes deal stage, timeline, contact data,
 * and email/thread activity → returns a risk score + risk factors + actions.
 *
 * Pattern: the hub's CRM becomes intelligent — deals are scored for risk,
 * not just tracked.
 */
import { db, now } from "@/lib/db";
import * as ml from "@/lib/ml/logistic";

export interface DealRiskScore {
  dealId: string;
  risk: number;           // 0-1 (0 = safe, 1 = critical)
  riskLevel: "safe" | "watch" | "at-risk" | "critical";
  riskFactors: { factor: string; evidence: string; severity: number }[];
  recommendedActions: { action: string; owner: string; urgency: "low" | "medium" | "high" }[];
  summary: string;

/**
 * Funnel simulator — given impressions/CTR/CVR at each step, project
 * revenue and find the leakiest step. Helps a marketer stop guessing
 * where the funnel breaks.
 */
import { db } from "@/lib/db";

export interface FunnelStep {
  name: string;
  impressions: number;
  ctr: number; // 0..1 — rate at which step advances
  value: number; // dollars per conversion at this step
}

